#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        int *arr = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &arr[i]);
        int first = 1;
        for (int i = 0; i < N; ++i) {
            if (arr[i] & 1) {
                if (!first) printf(" ");
                printf("%d", arr[i]);
                first = 0;
            }
        }
        for (int i = 0; i < N; ++i) {
            if ((arr[i] & 1) == 0) {
                if (!first) printf(" ");
                printf("%d", arr[i]);
                first = 0;
            }
        }
        printf("\n");
        free(arr);
    }
    return 0;
}

